## components/VoxelChicken.tsx

Added animation logic (bobbing, wing flapping, blinking) via internal CSS keyframes when `isAnimated` is true.

```tsx
import React from 'react';

interface VoxelChickenProps {
  size?: number;
  className?: string;
  emotion?: 'happy' | 'neutral' | 'thinking';
  isAnimated?: boolean;
}

const VoxelChicken: React.FC<VoxelChickenProps> = ({ size = 40, className = "", emotion = 'neutral', isAnimated = false }) => {
  // Keyframes for internal animation
  const animationStyles = isAnimated ? `
    @keyframes chicken-bob {
      0%, 100% { transform: translateY(0px); }
      50% { transform: translateY(-3px); }
    }
    @keyframes chicken-blink {
      0%, 48%, 52%, 100% { transform: scaleY(1); }
      50% { transform: scaleY(0.1); }
    }
    @keyframes chicken-wing-l {
      0%, 100% { transform: rotate(0deg); }
      50% { transform: rotate(-15deg); }
    }
    @keyframes chicken-wing-r {
      0%, 100% { transform: rotate(0deg); }
      50% { transform: rotate(15deg); }
    }
    .chicken-group { animation: chicken-bob 2s ease-in-out infinite; }
    .chicken-eyes { transform-box: fill-box; transform-origin: center; animation: chicken-blink 4s infinite; }
    .chicken-wing-l { transform-box: fill-box; transform-origin: top center; animation: chicken-wing-l 1s ease-in-out infinite; }
    .chicken-wing-r { transform-box: fill-box; transform-origin: top center; animation: chicken-wing-r 1s ease-in-out infinite; }
  ` : '';

  return (
    <svg 
      width={size} 
      height={size} 
      viewBox="0 0 100 100" 
      fill="none" 
      xmlns="http://www.w3.org/2000/svg"
      className={`${className} drop-shadow-sm`}
    >
      {isAnimated && <style>{animationStyles}</style>}

      <g className={isAnimated ? "chicken-group" : ""}>
        {/* Legs - Static relative to body in this group, so they bob with body */}
        <rect x="35" y="80" width="10" height="15" fill="#fbbf24" />
        <rect x="55" y="80" width="10" height="15" fill="#fbbf24" />

        {/* Body Shadow (for 3D depth) */}
        <rect x="20" y="30" width="60" height="60" rx="12" fill="#cbd5e1" />

        {/* Body Main */}
        <rect x="20" y="25" width="60" height="58" rx="12" fill="white" stroke="#e2e8f0" strokeWidth="2" />

        {/* Face details based on emotion */}
        <g className={isAnimated ? "chicken-eyes" : ""}>
            {emotion === 'thinking' ? (
                <>
                    <rect x="30" y="42" width="10" height="4" rx="2" fill="#1e293b" />
                    <rect x="60" y="42" width="10" height="4" rx="2" fill="#1e293b" />
                </>
            ) : (
                <>
                    <rect x="30" y="45" width="8" height="8" rx="2" fill="#1e293b" />
                    <rect x="62" y="45" width="8" height="8" rx="2" fill="#1e293b" />
                    {/* White reflection in eyes - hide when blinking or keep part of eye group */}
                    <rect x="32" y="46" width="3" height="3" fill="white" />
                    <rect x="64" y="46" width="3" height="3" fill="white" />
                </>
            )}
        </g>

        {/* Comb (Red top) */}
        <rect x="40" y="5" width="10" height="20" rx="2" fill="#ef4444" />
        <rect x="50" y="10" width="10" height="15" rx="2" fill="#ef4444" />
        <rect x="30" y="15" width="10" height="10" rx="2" fill="#ef4444" />

        {/* Beak */}
        <rect x="45" y="55" width="10" height="10" rx="2" fill="#f59e0b" />

        {/* Wattle (Red part under beak) */}
        <rect x="47" y="65" width="6" height="8" rx="3" fill="#ef4444" />

        {/* Wing (Left) */}
        <rect className={isAnimated ? "chicken-wing-l" : ""} x="12" y="50" width="12" height="20" rx="4" fill="white" stroke="#e2e8f0" strokeWidth="2" />

        {/* Wing (Right) */}
        <rect className={isAnimated ? "chicken-wing-r" : ""} x="76" y="50" width="12" height="20" rx="4" fill="white" stroke="#e2e8f0" strokeWidth="2" />
      </g>

    </svg>
  );
};

export default VoxelChicken;
