// List of mathematical terms to automatically highlight
const MATH_KEYWORDS = [
  'Derivative', 'Integral', 'Limit', 'Matrix', 'Vector', 'Eigenvector', 'Eigenvalue',
  'Determinant', 'Inverse', 'Linear Algebra', 'Calculus', 'Function', 'Graph', 
  'Discrete Math', 'Set Theory', 'Combinatorics', 'Probability', 'Statistics',
  'Logarithm', 'Exponential', 'Trigonometry', 'Sine', 'Cosine', 'Tangent',
  'Gradient', 'Divergence', 'Curl', 'Manifold', 'Topology', 'Equation',
  'Subspace', 'Basis', 'Dimension', 'Rank', 'Nullspace', 'Transformation',
  'Convergence', 'Divergence', 'Series', 'Sequence', 'Continuity', 'Taylor',
  'Fourier', 'Laplace', 'Differential', 'Partial', 'Chain Rule'
];

// Helper to format text with bold definitions and math keywords
const FormattedText: React.FC<{ text: string }> = ({ text }) => {
  // 1. Create a regex for bold text (**text**)
  // 2. Create a regex for keywords from MATH_KEYWORDS (case-insensitive)
  const keywordPattern = MATH_KEYWORDS.map(k => k.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|');
  const regex = new RegExp(`(\\*\\*.*?\\*\\*)|\\b(${keywordPattern})\\b`, 'gi');

  const parts = text.split(regex);

  return (
    <span>
      {parts.map((part, i) => {
        if (!part) return null;

        // Handle Bold
        if (part.startsWith('**') && part.endsWith('**')) {
          return (
            <strong key={i} className="text-brand-blue dark:text-brand-blue font-extrabold">
              {part.slice(2, -2)}
            </strong>
          );
        }

        // Handle Keyword Highlight (case-insensitive check)
        const isKeyword = MATH_KEYWORDS.some(k => k.toLowerCase() === part.toLowerCase());
        if (isKeyword) {
          return (
            <span 
              key={i} 
              className="px-1 py-0.5 rounded bg-brand-blue/10 dark:bg-brand-blue/20 text-brand-blue dark:text-brand-blue font-bold decoration-brand-blue/30 underline-offset-4 decoration-2"
            >
              {part}
            </span>
          );
        }

        return <span key={i}>{part}</span>;
      })}
    </span>
  );
};

const STORAGE_KEY = 'mathlingo_chat_history';

const Whiteboard: React.FC<WhiteboardProps> = ({ initialTopic, onXPChange }) => {
  // Initialize from LocalStorage or default
  const [messages, setMessages] = useState<Message[]>(() => {
    try {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) {
            return JSON.parse(saved);
        }
    } catch (e) {
        console.error("Failed to load chat history", e);
    }

    return [
        {
          id: 'welcome',
          role: 'model',
          text: initialTopic 
            ? `Cluck cluck! Welcome to the **${initialTopic}** coop! Let's hatch some solutions.` 
            : "Hi! I'm **Professor Cluck**. Pick a topic or ask me anything to get started!",
          timestamp: Date.now(),
          visual: { type: VisualType.NONE },
          suggestedActions: initialTopic 
            ? [`Show me a ${initialTopic} example`, `Define ${initialTopic}`, "Quiz me"] 
            : ["Visualize a Function", "Show me a Graph Tree", "Matrix Multiplication", "Explain Calculus"]
        }
    ];
  });

  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showKeyboard, setShowKeyboard] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Persist messages whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSend = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setShowKeyboard(false);
    setIsLoading(true);

    try {
        const responseMsg = await sendMessageToGemini(messages, text); 
        setMessages(prev => [...prev, responseMsg]);

        // Award XP for interaction
        if (onXPChange) onXPChange(10);

    } catch (e) {
        console.error(e);
    } finally {
        setIsLoading(false);
    }
  };

  const handleClear = () => {
      if (window.confirm("Clear chat history?")) {
          const defaultMsg: Message = {
            id: Date.now().toString(),
            role: 'model',
            text: "Coop cleaned! Ready for fresh questions.",
            visual: { type: VisualType.NONE },
            suggestedActions: ["Start Algebra", "Start Calculus", "Start Graphs"],
            timestamp: Date.now()
          };
          setMessages([defaultMsg]);
          localStorage.removeItem(STORAGE_KEY);
      }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend(inputText);
    }
  };

  const insertSymbol = (symbol: string) => {
    setInputText(prev => prev + symbol);
  };

  const deleteChar = () => {
    setInputText(prev => prev.slice(0, -1));
  };

  // Get the last message's suggestions, or default empty
  const lastModelMessage = [...messages].reverse().find(m => m.role === 'model');
  const currentSuggestions = lastModelMessage?.suggestedActions || [];

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] dark:bg-slate-950 relative overflow-hidden font-sans transition-colors duration-300">
        {/* Infinite Grid Background */}
        <div className="absolute inset-0 z-0 opacity-[0.4] dark:opacity-[0.1]" 
             style={{ 
                 backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)', 
                 backgroundSize: '24px 24px' 
             }}>
        </div>

        {/* Main Workspace Area */}
        <div className={`flex-1 overflow-y-auto z-10 p-4 pb-48 scrollbar-hide transition-all duration-300 ${showKeyboard ? 'pb-[320px]' : ''}`}>
            <div className="max-w-4xl mx-auto space-y-8">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-500`}>

                        {/* Avatar Label */}
                        <div className={`flex items-end gap-2 mb-2 px-1 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                            {msg.role === 'model' && (
                                <div className="mb-[-10px] z-10">
                                    <VoxelChicken size={50} />
                                </div>
                            )}
                            {msg.role === 'user' && (
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm border-2 bg-indigo-100 dark:bg-indigo-900 border-indigo-200 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400`}>
                                    <User size={20} />
                                </div>
                            )}

                            <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">
                                {msg.role === 'user' ? 'You' : 'Prof. Cluck'}
                            </span>
                        </div>

                        {/* Message Card */}
                        <div className={`max-w-[90%] md:max-w-[75%] p-5 rounded-3xl shadow-sm text-lg leading-relaxed border-b-4 relative transition-colors duration-300
                            ${msg.role === 'user' 
                                ? 'bg-indigo-500 text-white border-indigo-700 rounded-tr-sm' 
                                : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-200 rounded-tl-sm ml-4'
                            }`}>
                            <p><FormattedText text={msg.text} /></p>
                        </div>

                        {/* Visualization Card */}
                        {msg.visual && msg.visual.type !== VisualType.NONE && (
                            <div className="mt-4 ml-4 w-full max-w-2xl bg-white dark:bg-slate-900 p-2 rounded-3xl border-2 border-slate-200 dark:border-slate-800 shadow-[0_8px_0_rgb(226,232,240)] dark:shadow-[0_8px_0_rgb(30,41,59)] overflow-hidden transition-colors">
                                <div className="h-[350px] md:h-[450px] w-full">
                                    {msg.visual.type === VisualType.PLOT && msg.visual.plotData && (
                                        <PlotVis data={msg.visual.plotData} />
                                    )}
                                    {msg.visual.type === VisualType.GRAPH && msg.visual.graphData && (
                                        <GraphVis data={msg.visual.graphData} />
                                    )}
                                    {msg.visual.type === VisualType.MATRIX && msg.visual.matrixData && (
                                        <div className="h-full flex items-center justify-center">
                                            <MatrixVis data={msg.visual.matrixData} />
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                ))}

                {isLoading && (
                     <div className="flex flex-col items-start gap-2 animate-pulse">
                         <div className="flex items-end gap-2 px-1">
                             <div className="mb-[-10px] z-10">
                                <VoxelChicken size={50} emotion="thinking" />
                             </div>
                             <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">Pecking...</span>
                         </div>
                        <div className="bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 p-4 rounded-3xl rounded-tl-sm shadow-sm ml-4 transition-colors">
                            <Loader2 className="animate-spin text-brand-green" size={24} />
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>
        </div>

        {/* Input Area + Keyboard */}
        <div className="absolute bottom-0 left-0 right-0 z-20 flex flex-col">
            {/* Gradient Fade */}
            <div className="h-12 bg-gradient-to-t from-slate-100 dark:from-slate-950 to-transparent pointer-events-none" />

            <div className="bg-slate-100/90 dark:bg-slate-900/90 backdrop-blur-md border-t border-slate-200 dark:border-slate-800 pb-2 pt-2 px-4 transition-colors">
                <div className="max-w-4xl mx-auto flex flex-col gap-3">

                    {/* Suggested Actions Chips */}
                    {!isLoading && !showKeyboard && currentSuggestions.length > 0 && (
                        <div className="flex flex-wrap gap-2 justify-center md:justify-start mb-2">
                            {currentSuggestions.map((action, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => handleSend(action)}
                                    className="px-5 py-3 rounded-2xl bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 shadow-[0_4px_0_#e2e8f0] dark:shadow-[0_4px_0_#1e293b] hover:translate-y-1 hover:shadow-none hover:border-brand-blue hover:text-brand-blue dark:hover:text-brand-blue font-bold text-slate-600 dark:text-slate-300 transition-all text-sm md:text-base flex items-center gap-2 group"
                                >
                                    {action}
                                    <ArrowRight size={16} className="opacity-0 group-hover:opacity-100 transition-opacity -ml-2 group-hover:ml-0" />
                                </button>
                            ))}
                        </div>
                    )}

                    {/* Input Bar */}
                    <div className="flex items-center gap-3 pb-4">
                         <button 
                            className="p-3 bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-2xl text-slate-400 dark:text-slate-500 hover:text-brand-red hover:border-brand-red transition-colors shadow-sm"
                            title="Clear History" 
                            onClick={handleClear}
                        >
                            <Eraser size={20} />
                        </button>

                        <div className="flex-1 relative">
                            <input
                                type="text"
                                value={inputText}
                                onChange={(e) => setInputText(e.target.value)}
                                onKeyDown={handleKeyPress}
                                placeholder="Ask Prof. Cluck..."
                                disabled={isLoading}
                                className={`w-full p-4 pr-12 rounded-2xl border-2 outline-none transition-all font-medium text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 focus:border-brand-blue focus:shadow-[0_4px_0_#1CB0F6]`}
                            />
                            <button 
                                onClick={() => setShowKeyboard(!showKeyboard)}
                                className={`absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 dark:text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 hover:text-brand-blue transition-colors ${showKeyboard ? 'text-brand-blue bg-blue-50 dark:bg-blue-900/30' : ''}`}
                            >
                                {showKeyboard ? <X size={20} /> : <Keyboard size={20} />}
                            </button>
                        </div>

                        <button 
                            onClick={() => handleSend(inputText)}
                            disabled={!inputText.trim() || isLoading}
                            className={`p-4 rounded-2xl transition-all duration-200 flex items-center justify-center
                                ${inputText.trim() && !isLoading 
                                    ? 'bg-brand-green text-white shadow-[0_4px_0_#46A302] hover:translate-y-1 hover:shadow-none' 
                                    : 'bg-slate-200 dark:bg-slate-800 text-slate-300 dark:text-slate-600 cursor-not-allowed border-2 border-transparent dark:border-slate-700'
                                }`}
                        >
                            <Send size={20} />
                        </button>
                    </div>
                </div>
            </div>

            {/* Custom Math Keyboard */}
            <MathKeyboard 
                isOpen={showKeyboard} 
                onInsert={insertSymbol} 
