// List of mathematical terms to automatically highlight
const MATH_KEYWORDS = [
  'Derivative', 'Integral', 'Limit', 'Matrix', 'Vector', 'Eigenvector', 'Eigenvalue',
  'Determinant', 'Inverse', 'Linear Algebra', 'Calculus', 'Function', 'Graph', 
  'Discrete Math', 'Set Theory', 'Combinatorics', 'Probability', 'Statistics',
  'Logarithm', 'Exponential', 'Trigonometry', 'Sine', 'Cosine', 'Tangent',
  'Gradient', 'Divergence', 'Curl', 'Manifold', 'Topology', 'Equation',
  'Subspace', 'Basis', 'Dimension', 'Rank', 'Nullspace', 'Transformation',
  'Convergence', 'Divergence', 'Series', 'Sequence', 'Continuity', 'Taylor',
  'Fourier', 'Laplace', 'Differential', 'Partial', 'Chain Rule'
];

/**
 * Renders a LaTeX string using KaTeX.
 */
const MathRenderer: React.FC<{ tex: string; displayMode?: boolean }> = ({ tex, displayMode = false }) => {
  const html = React.useMemo(() => {
    try {
      if (window.katex) {
        return window.katex.renderToString(tex, {
          displayMode,
          throwOnError: false,
        });
      }
      return tex;
    } catch (e) {
      console.error("KaTeX Error:", e);
      return tex;
    }
  }, [tex, displayMode]);

  return <span className={displayMode ? "block my-4" : "inline-block"} dangerouslySetInnerHTML={{ __html: html }} />;
};

/**
 * Formats text with support for Bold, LaTeX, and Key Terms.
 */
const FormattedText: React.FC<{ text: string }> = ({ text }) => {
  const keywordPattern = MATH_KEYWORDS.map(k => k.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|');

  // Regex pattern for:
  // 1. Double Dollar LaTeX ($$ ... $$)
  // 2. Single Dollar LaTeX ($ ... $)
  // 3. Bold (** ... **)
  // 4. Keywords
  const regex = new RegExp(`(\\$\\$[\\s\\S]*?\\$\\$)|(\\$.*?\\$)|(\\*\\*.*?\\*\\*)|\\b(${keywordPattern})\\b`, 'gi');

  const parts = text.split(regex);

  return (
    <div className="whitespace-pre-wrap">
      {parts.map((part, i) => {
        if (!part) return null;

        // Block Math
        if (part.startsWith('$$') && part.endsWith('$$')) {
          return <MathRenderer key={i} tex={part.slice(2, -2)} displayMode={true} />;
        }

        // Inline Math
        if (part.startsWith('$') && part.endsWith('$')) {
          return <MathRenderer key={i} tex={part.slice(1, -1)} />;
        }

        // Handle Bold
        if (part.startsWith('**') && part.endsWith('**')) {
          return (
            <strong key={i} className="text-brand-blue dark:text-brand-blue font-extrabold">
              {part.slice(2, -2)}
            </strong>
          );
        }

        // Handle Keyword Highlight
        const isKeyword = MATH_KEYWORDS.some(k => k.toLowerCase() === part.toLowerCase());
        if (isKeyword) {
          return (
            <span 
              key={i} 
              className="px-1 py-0.5 rounded bg-brand-blue/10 dark:bg-brand-blue/20 text-brand-blue dark:text-brand-blue font-bold decoration-brand-blue/30 underline-offset-4 decoration-2"
            >
              {part}
            </span>
          );
        }

        return <span key={i}>{part}</span>;
      })}
    </div>
  );
};

const STORAGE_KEY = 'mathlingo_chat_history';

const Whiteboard: React.FC<WhiteboardProps> = ({ initialTopic, onXPChange }) => {
  const [messages, setMessages] = useState<Message[]>(() => {
    try {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) return JSON.parse(saved);
    } catch (e) {
        console.error("Failed to load chat history", e);
    }

    return [
        {
          id: 'welcome',
          role: 'model',
          text: initialTopic 
            ? `Cluck cluck! Welcome to the **${initialTopic}** coop! Let's hatch some solutions.` 
            : "Hi! I'm **Professor Cluck**. Pick a topic or ask me anything to get started!",
          timestamp: Date.now(),
          visual: { type: VisualType.NONE },
          suggestedActions: initialTopic 
            ? [`Show me a ${initialTopic} example`, `Define ${initialTopic}`, "Quiz me"] 
            : ["Visualize a Function", "Show me a Graph Tree", "Matrix Multiplication", "Explain Calculus"]
        }
    ];
  });

  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [showKeyboard, setShowKeyboard] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSend = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: text,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setShowKeyboard(false);
    setIsLoading(true);

    try {
        const responseMsg = await sendMessageToGemini(messages, text); 
        setMessages(prev => [...prev, responseMsg]);
        if (onXPChange) onXPChange(10);
    } catch (e) {
        console.error(e);
    } finally {
        setIsLoading(false);
    }
  };

  const handleClear = () => {
      if (window.confirm("Clear chat history?")) {
          const defaultMsg: Message = {
            id: Date.now().toString(),
            role: 'model',
            text: "Coop cleaned! Ready for fresh questions.",
            visual: { type: VisualType.NONE },
            suggestedActions: ["Start Algebra", "Start Calculus", "Start Graphs"],
            timestamp: Date.now()
          };
          setMessages([defaultMsg]);
          localStorage.removeItem(STORAGE_KEY);
      }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend(inputText);
    }
  };

  const insertSymbol = (symbol: string) => {
    setInputText(prev => prev + symbol);
  };

  const deleteChar = () => {
    setInputText(prev => prev.slice(0, -1));
  };

  const lastModelMessage = [...messages].reverse().find(m => m.role === 'model');
  const currentSuggestions = lastModelMessage?.suggestedActions || [];

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] dark:bg-slate-950 relative overflow-hidden font-sans transition-colors duration-300">
        <div className="absolute inset-0 z-0 opacity-[0.4] dark:opacity-[0.1]" 
             style={{ 
                 backgroundImage: 'radial-gradient(#cbd5e1 1px, transparent 1px)', 
                 backgroundSize: '24px 24px' 
             }}>
        </div>

        <div className={`flex-1 overflow-y-auto z-10 p-4 pb-48 scrollbar-hide transition-all duration-300 ${showKeyboard ? 'pb-[320px]' : ''}`}>
            <div className="max-w-4xl mx-auto space-y-8">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2 duration-500`}>

                        <div className={`flex items-end gap-2 mb-2 px-1 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                            {msg.role === 'model' && (
                                <div className="mb-[-10px] z-10">
                                    <VoxelChicken size={50} />
                                </div>
                            )}
                            {msg.role === 'user' && (
                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm border-2 bg-indigo-100 dark:bg-indigo-900 border-indigo-200 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400`}>
                                    <User size={20} />
                                </div>
                            )}

                            <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">
                                {msg.role === 'user' ? 'You' : 'Prof. Cluck'}
                            </span>
                        </div>

                        <div className={`max-w-[90%] md:max-w-[85%] p-5 rounded-3xl shadow-sm text-lg leading-relaxed border-b-4 relative transition-colors duration-300
                            ${msg.role === 'user' 
                                ? 'bg-indigo-500 text-white border-indigo-700 rounded-tr-sm' 
                                : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-200 rounded-tl-sm ml-4'
                            }`}>
                            <FormattedText text={msg.text} />
                        </div>

                        {msg.visual && msg.visual.type !== VisualType.NONE && (
                            <div className="mt-4 ml-4 w-full max-w-2xl bg-white dark:bg-slate-900 p-2 rounded-3xl border-2 border-slate-200 dark:border-slate-800 shadow-[0_8px_0_rgb(226,232,240)] dark:shadow-[0_8px_0_rgb(30,41,59)] overflow-hidden transition-colors">
                                <div className="h-[350px] md:h-[450px] w-full">
                                    {msg.visual.type === VisualType.PLOT && msg.visual.plotData && (
                                        <PlotVis data={msg.visual.plotData} />
                                    )}
                                    {msg.visual.type === VisualType.GRAPH && msg.visual.graphData && (
                                        <GraphVis data={msg.visual.graphData} />
                                    )}
                                    {msg.visual.type === VisualType.MATRIX && msg.visual.matrixData && (
                                        <div className="h-full flex items-center justify-center">
                                            <MatrixVis data={msg.visual.matrixData} />
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                ))}

                {isLoading && (
                     <div className="flex flex-col items-start gap-2 animate-pulse">
                         <div className="flex items-end gap-2 px-1">
                             <div className="mb-[-10px] z-10">
                                <VoxelChicken size={50} emotion="thinking" />
                             </div>
                             <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">Pecking...</span>
                         </div>
                        <div className="bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 p-4 rounded-3xl rounded-tl-sm shadow-sm ml-4 transition-colors">
                            <Loader2 className="animate-spin text-brand-green" size={24} />
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>
        </div>

        <div className="absolute bottom-0 left-0 right-0 z-20 flex flex-col">
            <div className="h-12 bg-gradient-to-t from-slate-100 dark:from-slate-950 to-transparent pointer-events-none" />

            <div className="bg-slate-100/90 dark:bg-slate-900/90 backdrop-blur-md border-t border-slate-200 dark:border-slate-800 pb-2 pt-2 px-4 transition-colors">
                <div className="max-w-4xl mx-auto flex flex-col gap-3">

                    {!isLoading && !showKeyboard && currentSuggestions.length > 0 && (
                        <div className="flex flex-wrap gap-2 justify-center md:justify-start mb-2">
                            {currentSuggestions.map((action, idx) => (
                                <button
                                    key={idx}
                                    onClick={() => handleSend(action)}
                                    className="px-5 py-3 rounded-2xl bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 shadow-[0_4px_0_#e2e8f0] dark:shadow-[0_4px_0_#1e293b] hover:translate-y-1 hover:shadow-none hover:border-brand-blue hover:text-brand-blue dark:hover:text-brand-blue font-bold text-slate-600 dark:text-slate-300 transition-all text-sm md:text-base flex items-center gap-2 group"
                                >
                                    {action}
                                    <ArrowRight size={16} className="opacity-0 group-hover:opacity-100 transition-opacity -ml-2 group-hover:ml-0" />
                                </button>
                            ))}
                        </div>
                    )}

                    <div className="flex items-center gap-3 pb-4">
                         <button 
                            className="p-3 bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-2xl text-slate-400 dark:text-slate-500 hover:text-brand-red hover:border-brand-red transition-colors shadow-sm"
                            title="Clear History" 
                            onClick={handleClear}
                        >
                            <Eraser size={20} />
                        </button>

                        <div className="flex-1 relative">
                            <input
                                type="text"
                                value={inputText}
                                onChange={(e) => setInputText(e.target.value)}
                                onKeyDown={handleKeyPress}
                                placeholder="Ask Prof. Cluck..."
                                disabled={isLoading}
                                className={`w-full p-4 pr-12 rounded-2xl border-2 outline-none transition-all font-medium text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 focus:border-brand-blue focus:shadow-[0_4px_0_#1CB0F6]`}
                            />
                            <button 
                                onClick={() => setShowKeyboard(!showKeyboard)}
                                className={`absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 dark:text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 hover:text-brand-blue transition-colors ${showKeyboard ? 'text-brand-blue bg-blue-50 dark:bg-blue-900/30' : ''}`}
                            >
                                {showKeyboard ? <X size={20} /> : <Keyboard size={20} />}
                            </button>
                        </div>

                        <button 
                            onClick={() => handleSend(inputText)}
                            disabled={!inputText.trim() || isLoading}
                            className={`p-4 rounded-2xl transition-all duration-200 flex items-center justify-center
                                ${inputText.trim() && !isLoading 
                                    ? 'bg-brand-green text-white shadow-[0_4px_0_#46A302] hover:translate-y-1 hover:shadow-none' 
                                    : 'bg-slate-200 dark:bg-slate-800 text-slate-300 dark:text-slate-600 cursor-not-allowed border-2 border-transparent dark:border-slate-700'
                                }`}
                        >
                            <Send size={20} />
                        </button>
                    </div>
                </div>
            </div>

            <MathKeyboard 
                isOpen={showKeyboard} 
                onInsert={insertSymbol} 
                onDelete={deleteChar} 
                onEnter={() => handleSend(inputText)} 
            />
        </div>
    </div>
  );
};

export default Whiteboard;

export enum VisualType {
  NONE = 'NONE',
  PLOT = 'PLOT',       // 2D functions like y = x^2
  PLOT3D = 'PLOT3D',   // 3D surfaces like z = x^2 + y^2
  GRAPH = 'GRAPH',     // Nodes and edges (trees, graph theory)
  FLOWCHART = 'FLOWCHART', // Algorithms or logical flows
  MATRIX = 'MATRIX'    // Matrix operations visual
}

export interface GraphNode {
  id: string;
  label?: string;
  group?: number;
}

export interface GraphLink {
  source: string;
  target: string;
  value?: number;
  label?: string;
}

export interface GraphData {
  nodes: GraphNode[];
  links: GraphLink[];
}

export interface PlotPoint {
  x: number;
  y: number;
}

export interface PlotData {
  points: PlotPoint[];
  label: string;
  domain: [number, number];
}

export interface Plot3DData {
  formula: string; // z in terms of x and y
  xRange: [number, number];
  yRange: [number, number];
  label: string;
}

export interface FlowchartNode {
  id: string;
  label: string;
  type: 'start' | 'step' | 'decision' | 'end';
}

export interface FlowchartData {
  nodes: FlowchartNode[];
  links: GraphLink[];
}

export interface MatrixData {
  matrix: number[][];
  label?: string;
}

export interface VisualContent {
  type: VisualType;
  graphData?: GraphData;
  plotData?: PlotData;
  plot3DData?: Plot3DData;
  matrixData?: MatrixData;
  flowchartData?: FlowchartData;
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  visual?: VisualContent;
  suggestedActions?: string[]; 
  timestamp: number;
}

export interface Topic {
  id: string;
  name: string;
  description: string;
  color: string;
  icon: string;
  completed: number; // 0 to 100
}

export interface MathResponseSchema {
  explanation: string;
  visualType: string; // "PLOT" | "PLOT3D" | "GRAPH" | "FLOWCHART" | "MATRIX" | "NONE"
  suggestedActions: string[];
  // For Plot
  plotFormula?: string;
  plotDomainMin?: number;
  plotDomainMax?: number;
  // For Plot3D
  plot3DFormula?: string; // e.g. "Math.pow(x, 2) + Math.pow(y, 2)"
  // For Graph/Flowchart
  graphNodes?: { id: string; label: string; group?: number; type?: string }[];
  graphLinks?: { source: string; target: string; label?: string }[];
  // For Matrix
  matrixRows?: number[][];
}

export type View = 'auth' | 'path' | 'practice' | 'leaderboard' | 'shop';

import { GoogleGenAI, Type } from "@google/genai";
import { Message, VisualType, VisualContent, MathResponseSchema } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const modelId = "gemini-2.5-flash";

const systemInstruction = `
You are Professor Cluck, a brilliant, enthusiastic Voxel Chicken math tutor for college students.
Your world is made of blocks and numbers! 
Your goal is to explain complex math concepts simply and visually.

Visual Types:
1. PLOT (2D): Use for functions f(x). Formula: valid JS math string using 'x'.
2. PLOT3D (3D): Use for surfaces f(x,y). Formula: valid JS math string using 'x' and 'y' (e.g. "Math.sin(x) * Math.cos(y)").
3. GRAPH: Use for abstract structures, trees, networking.
4. FLOWCHART: Use for algorithms, logical processes. Node types: 'start', 'step', 'decision', 'end'.
5. MATRIX: Use for linear algebra.

Math Content Rules:
- ALWAYS use LaTeX with single ($) or double ($$) dollar signs.
- Be precise and encouraging.

Response Format:
You MUST respond using the specified JSON schema.
Always provide 'explanation' and 'suggestedActions'.
`;

export const sendMessageToGemini = async (history: Message[], userMessage: string): Promise<Message> => {
  try {
    const contents = history.map(msg => ({
      role: msg.role,
      parts: [{ text: msg.text }]
    }));

    contents.push({
      role: 'user',
      parts: [{ text: userMessage }]
    });

    const response = await ai.models.generateContent({
      model: modelId,
      contents: contents,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            explanation: { type: Type.STRING },
            visualType: { type: Type.STRING, enum: ["PLOT", "PLOT3D", "GRAPH", "FLOWCHART", "MATRIX", "NONE"] },
            suggestedActions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            plotFormula: { type: Type.STRING },
            plotDomainMin: { type: Type.NUMBER },
            plotDomainMax: { type: Type.NUMBER },
            plot3DFormula: { type: Type.STRING },
            graphNodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  label: { type: Type.STRING },
                  group: { type: Type.INTEGER },
                  type: { type: Type.STRING } // For Flowchart
                }
              }
            },
            graphLinks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  source: { type: Type.STRING },
                  target: { type: Type.STRING },
                  label: { type: Type.STRING }
                }
              }
            },
            matrixRows: {
              type: Type.ARRAY,
              items: {
                type: Type.ARRAY,
                items: { type: Type.NUMBER }
              }
            }
          },
          required: ["explanation", "visualType", "suggestedActions"]
        }
      }
    });

    const responseText = response.text;
    if (!responseText) throw new Error("No response from Gemini");

    const data = JSON.parse(responseText) as MathResponseSchema;
    let visual: VisualContent = { type: VisualType.NONE };

    if (data.visualType === "PLOT" && data.plotFormula) {
      const points = [];
      const min = data.plotDomainMin ?? -10;
      const max = data.plotDomainMax ?? 10;
      const step = (max - min) / 100;
      try {
        const func = new Function('x', `return ${data.plotFormula};`);
        for (let x = min; x <= max; x += step) {
            const y = func(x);
            if (!isNaN(y) && isFinite(y)) points.push({ x: parseFloat(x.toFixed(2)), y: parseFloat(y.toFixed(2)) });
        }
        visual = { type: VisualType.PLOT, plotData: { points, label: `y = ${data.plotFormula}`, domain: [min, max] } };
      } catch (e) { console.error(e); }

    } else if (data.visualType === "PLOT3D" && data.plot3DFormula) {
        visual = { 
            type: VisualType.PLOT3D, 
            plot3DData: { 
                formula: data.plot3DFormula, 
                xRange: [-5, 5], 
                yRange: [-5, 5], 
                label: `z = ${data.plot3DFormula}` 
            } 
        };
    } else if (data.visualType === "FLOWCHART" && data.graphNodes && data.graphLinks) {
        visual = {
            type: VisualType.FLOWCHART,
            flowchartData: {
                nodes: data.graphNodes.map(n => ({ id: n.id, label: n.label, type: (n.type as any) || 'step' })),
                links: data.graphLinks
            }
        };
    } else if (data.visualType === "GRAPH" && data.graphNodes && data.graphLinks) {
        visual = {
            type: VisualType.GRAPH,
            graphData: { nodes: data.graphNodes, links: data.graphLinks }
        };
    } else if (data.visualType === "MATRIX" && data.matrixRows) {
        visual = {
            type: VisualType.MATRIX,
            matrixData: { matrix: data.matrixRows, label: "Matrix" }
        };
    }

    return {
      id: Date.now().toString(),
      role: 'model',
      text: data.explanation,
      visual: visual,
      suggestedActions: data.suggestedActions || ["Explain more", "Show an example"],
      timestamp: Date.now()
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      id: Date.now().toString(),
      role: 'model',
      text: "Squawk! I'm having trouble connecting to the math universe right now. Try again?",
      visual: { type: VisualType.NONE },
      suggestedActions: ["Try again"],
      timestamp: Date.now()
    };
  }
};

import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { Plot3DData } from '../../types';

interface Plot3DVisProps {
  data: Plot3DData;
}

const Plot3DVis: React.FC<Plot3DVisProps> = ({ data }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight;

    // Scene setup
    const scene = new THREE.Scene();
    scene.background = new THREE.Color(0xf8fafc);
    if (document.documentElement.classList.contains('dark')) {
      scene.background = new THREE.Color(0x0f172a);
    }

    const camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 1000);
    camera.position.set(10, 10, 10);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(width, height);
    containerRef.current.appendChild(renderer.domElement);

    // Lights
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);
    const directionalLight = new THREE.DirectionalLight(0xffffff, 1);
    directionalLight.position.set(10, 20, 10);
    scene.add(directionalLight);

    // Axis Helper
    const axes = new THREE.AxesHelper(6);
    scene.add(axes);

    // Generate Surface
    const segments = 50;
    const geometry = new THREE.PlaneGeometry(10, 10, segments, segments);
    geometry.rotateX(-Math.PI / 2);

    let func;
    try {
      func = new Function('x', 'y', `return ${data.formula};`);
    } catch (e) {
      func = (x: number, y: number) => 0;
    }

    const positions = geometry.attributes.position;
    for (let i = 0; i < positions.count; i++) {
      const x = positions.getX(i);
      const y = positions.getZ(i); // Plane is rotated, so Z is now Y in world space
      try {
        const z = func(x, y);
        positions.setY(i, z);
      } catch (e) {
        positions.setY(i, 0);
      }
    }
    geometry.computeVertexNormals();

    const material = new THREE.MeshPhongMaterial({
      color: 0x1CB0F6,
      side: THREE.DoubleSide,
      flatShading: false,
      wireframe: false,
      transparent: true,
      opacity: 0.9
    });
    const mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);

    // Wireframe Overlay
    const wireframe = new THREE.WireframeGeometry(geometry);
    const line = new THREE.LineSegments(wireframe);
    line.material.opacity = 0.25;
    line.material.transparent = true;
    line.material.color = new THREE.Color(0xffffff);
    scene.add(line);

    // Interaction (Simple Mouse Rotation)
    let isDragging = false;
    let previousMousePosition = { x: 0, y: 0 };

    const onMouseDown = (e: MouseEvent) => { isDragging = true; };
    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        const deltaMove = { x: e.offsetX - previousMousePosition.x, y: e.offsetY - previousMousePosition.y };
        const rotateQuaternion = new THREE.Quaternion().setFromEuler(new THREE.Euler(
          THREE.MathUtils.degToRad(deltaMove.y * 0.5),
          THREE.MathUtils.degToRad(deltaMove.x * 0.5),
          0,
          'XYZ'
        ));
        scene.quaternion.multiplyQuaternions(rotateQuaternion, scene.quaternion);
      }
      previousMousePosition = { x: e.offsetX, y: e.offsetY };
    };
    const onMouseUp = () => { isDragging = false; };

    renderer.domElement.addEventListener('mousedown', onMouseDown);
    renderer.domElement.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);

    // Animation loop
    const animate = () => {
      requestAnimationFrame(animate);
      renderer.render(scene, camera);
    };
    animate();

    return () => {
      renderer.dispose();
      if (containerRef.current) {
          containerRef.current.removeChild(renderer.domElement);
      }
      renderer.domElement.removeEventListener('mousedown', onMouseDown);
      renderer.domElement.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [data]);

  return (
    <div className="w-full h-full relative group">
      <div className="absolute top-4 left-4 z-10 bg-white/80 dark:bg-slate-800/80 backdrop-blur-md p-2 rounded-xl border border-slate-200 dark:border-slate-700 pointer-events-none">
          <p className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1">3D Surface</p>
          <p className="text-sm font-mono font-bold text-brand-blue">{data.label}</p>
          <p className="text-[10px] text-slate-400 mt-1">Drag to rotate view</p>
      </div>
      <div ref={containerRef} className="w-full h-full cursor-move" />
    </div>
  );
};

