import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { FlowchartData } from '../../types';

interface FlowchartVisProps {
  data: FlowchartData;
}

const FlowchartVis: React.FC<FlowchartVisProps> = ({ data }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current || !data.nodes.length) return;

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const isDark = document.documentElement.classList.contains('dark');
    const linkColor = isDark ? "#475569" : "#cbd5e1";
    const textColor = isDark ? "#f1f5f9" : "#1e293b";

    // Setup Simulation with specific forces for hierarchy
    const simulation = d3.forceSimulation(data.nodes as any)
      .force("link", d3.forceLink(data.links).id((d: any) => d.id).distance(100))
      .force("charge", d3.forceManyBody().strength(-500))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("y", d3.forceY().strength(0.1))
      .force("x", d3.forceX().strength(0.1));

    // Marker for Arrows
    svg.append("defs").append("marker")
      .attr("id", "arrow")
      .attr("viewBox", "0 -5 10 10")
      .attr("refX", 55)
      .attr("refY", 0)
      .attr("markerWidth", 6)
      .attr("markerHeight", 6)
      .attr("orient", "auto")
      .append("path")
      .attr("d", "M0,-5L10,0L0,5")
      .attr("fill", linkColor);

    const link = svg.append("g")
      .selectAll("g")
      .data(data.links)
      .join("g");

    link.append("line")
      .attr("stroke", linkColor)
      .attr("stroke-width", 2)
      .attr("marker-end", "url(#arrow)");

    link.append("text")
        .text(d => d.label || "")
        .attr("fill", isDark ? "#94a3b8" : "#64748b")
        .attr("font-size", "10px")
        .attr("text-anchor", "middle")
        .attr("dy", -5);

    const node = svg.append("g")
      .selectAll("g")
      .data(data.nodes)
      .join("g")
      .call(d3.drag<any, any>()
        .on("start", (e, d) => { if (!e.active) simulation.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
        .on("drag", (e, d) => { d.fx = e.x; d.fy = e.y; })
        .on("end", (e, d) => { if (!e.active) simulation.alphaTarget(0); d.fx = null; d.fy = null; }));

    node.each(function(d: any) {
      const g = d3.select(this);
      const label = d.label;

      if (d.type === 'decision') {
          // Diamond shape
          g.append("path")
            .attr("d", "M 0 -35 L 50 0 L 0 35 L -50 0 Z")
            .attr("fill", "#FFC800")
            .attr("stroke", "white")
            .attr("stroke-width", 3);
      } else if (d.type === 'start' || d.type === 'end') {
          // Capsule
          g.append("rect")
            .attr("x", -50).attr("y", -20).attr("width", 100).attr("height", 40).attr("rx", 20)
            .attr("fill", d.type === 'start' ? "#58CC02" : "#FF4B4B")
            .attr("stroke", "white").attr("stroke-width", 3);
      } else {
          // Rectangle
          g.append("rect")
            .attr("x", -55).attr("y", -25).attr("width", 110).attr("height", 50).attr("rx", 8)
            .attr("fill", "#1CB0F6")
            .attr("stroke", "white").attr("stroke-width", 3);
      }

      g.append("text")
        .text(label)
        .attr("text-anchor", "middle")
        .attr("dy", ".35em")
        .attr("fill", "white")
        .attr("font-weight", "bold")
        .attr("font-size", "11px")
        .attr("pointer-events", "none");
    });

    simulation.on("tick", () => {
      link.select("line")
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      link.select("text")
        .attr("x", (d: any) => (d.source.x + d.target.x) / 2)
        .attr("y", (d: any) => (d.source.y + d.target.y) / 2);

      node.attr("transform", (d: any) => `translate(${d.x},${d.y})`);
    });

  }, [data]);

  return (
    <div className="w-full h-full min-h-[400px] bg-slate-50 dark:bg-slate-900/50 rounded-2xl border-2 border-slate-200 dark:border-slate-800 overflow-hidden transition-colors relative">
        <div className="absolute top-2 left-2 bg-white/80 dark:bg-slate-800/80 px-3 py-1 rounded-lg text-xs font-bold text-slate-500 z-10 uppercase tracking-widest">Process Flow</div>
        <svg ref={svgRef} className="w-full h-full" />
    </div>
  );
};

