    try {
        const saved = localStorage.getItem(STORAGE_KEY);
        if (saved) return JSON.parse(saved);
    } catch (e) { console.error(e); }

    return [
        {
          id: 'welcome',
          role: 'model',
          text: initialTopic 
            ? `Cluck cluck! Welcome to the **${initialTopic}** coop! Let's hatch some solutions.` 
            : "Hi! I'm **Professor Cluck**. Pick a topic or ask me anything to get started!",
          timestamp: Date.now(),
          visual: { type: VisualType.NONE },
          suggestedActions: initialTopic 
            ? [`Show me a ${initialTopic} example`, "Quiz me"] 
            : ["3D Paraboloid", "BFS Algorithm", "Matrix Rotation", "Tangent Plane"]
        }
    ];
  });

  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
