                         <button className="p-3 bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-2xl text-slate-400 hover:text-brand-red transition-colors" title="Clear History" onClick={() => { if (confirm("Clear history?")) { setMessages([]); localStorage.removeItem(STORAGE_KEY); } }}><Eraser size={20} /></button>
                        <div className="flex-1 relative">
                            <input type="text" value={inputText} onChange={(e) => setInputText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleSend(inputText)} placeholder="Ask Prof. Cluck..." disabled={isLoading} className="w-full p-4 pr-12 rounded-2xl border-2 outline-none font-medium text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 focus:border-brand-blue focus:shadow-[0_4px_0_#1CB0F6]" />
                            <button onClick={() => setShowKeyboard(!showKeyboard)} className={`absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-brand-blue ${showKeyboard ? 'text-brand-blue bg-blue-50 dark:bg-blue-900/30' : ''}`}>{showKeyboard ? <X size={20} /> : <Keyboard size={20} />}</button>
                        </div>
                        <button onClick={() => handleSend(inputText)} disabled={!inputText.trim() || isLoading} className={`p-4 rounded-2xl transition-all ${inputText.trim() && !isLoading ? 'bg-brand-green text-white shadow-[0_4px_0_#46A302] hover:translate-y-1 hover:shadow-none' : 'bg-slate-200 dark:bg-slate-800 text-slate-300 cursor-not-allowed'}`}><Send size={20} /></button>
                    </div>
                </div>
            </div>
            <MathKeyboard isOpen={showKeyboard} onInsert={(s) => setInputText(p => p + s)} onDelete={() => setInputText(p => p.slice(0, -1))} onEnter={() => handleSend(inputText)} />
        </div>
    </div>
  );
};

