import { GoogleGenAI, Type } from "@google/genai";
import { Message, VisualType, VisualContent, MathResponseSchema } from '../types';

const modelId = "gemini-3-pro-preview";

const systemInstruction = `
You are Professor Cluck, a brilliant, enthusiastic Voxel Chicken math tutor for college students.
Your world is made of blocks and numbers! 
Your goal is to explain complex math concepts (Calculus, Linear Algebra, Discrete Math, Graph Theory) simply and visually.

Visual Types:
1. PLOT (2D): Use for functions f(x). Formula: valid JS math string using 'x'.
2. PLOT3D (3D): Use for surfaces f(x,y). Formula: valid JS math string using 'x' and 'y' (e.g. "Math.sin(x) * Math.cos(y)").
3. GRAPH: Use for abstract structures, trees, networking.
4. FLOWCHART: Use for algorithms, logical processes. Node types: 'start', 'step', 'decision', 'end'.
5. MATRIX: Use for linear algebra.

Math Content Rules:
- ALWAYS use LaTeX with single ($) or double ($$) dollar signs.
- If the user provides an image, solve the math problem shown in the image with step-by-step logic.
- Be precise, technical, and encouraging.

Response Format:
You MUST respond using the specified JSON schema.
Always provide 'explanation' and 'suggestedActions'.
`;

export const sendMessageToGemini = async (history: Message[], userMessage: string, imageBase64?: string): Promise<Message> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const contents = history.map(msg => ({
      role: msg.role,
      parts: [
        { text: msg.text },
        ...(msg.image ? [{ inlineData: { data: msg.image.split(',')[1], mimeType: 'image/jpeg' } }] : [])
      ]
    }));

    const newUserParts: any[] = [{ text: userMessage }];
    if (imageBase64) {
      newUserParts.push({
        inlineData: {
          data: imageBase64.split(',')[1],
          mimeType: 'image/jpeg'
        }
      });
    }

    contents.push({
      role: 'user',
      parts: newUserParts
    });

    const response = await ai.models.generateContent({
      model: modelId,
      contents: contents,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            explanation: { type: Type.STRING },
            visualType: { type: Type.STRING, enum: ["PLOT", "PLOT3D", "GRAPH", "FLOWCHART", "MATRIX", "NONE"] },
            suggestedActions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            plotFormula: { type: Type.STRING },
            plotDomainMin: { type: Type.NUMBER },
            plotDomainMax: { type: Type.NUMBER },
            plot3DFormula: { type: Type.STRING },
            graphNodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  label: { type: Type.STRING },
                  group: { type: Type.INTEGER },
                  type: { type: Type.STRING } 
                }
              }
            },
            graphLinks: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  source: { type: Type.STRING },
                  target: { type: Type.STRING },
                  label: { type: Type.STRING }
                }
              }
            },
            matrixRows: {
              type: Type.ARRAY,
              items: {
                type: Type.ARRAY,
                items: { type: Type.NUMBER }
              }
            }
          },
          required: ["explanation", "visualType", "suggestedActions"]
        }
      }
    });

    const responseText = response.text;
    if (!responseText) throw new Error("No response from Gemini");

    const data = JSON.parse(responseText) as MathResponseSchema;
    let visual: VisualContent = { type: VisualType.NONE };

    // Logic for building visual data objects remains largely the same
    if (data.visualType === "PLOT" && data.plotFormula) {
      const points = [];
      const min = data.plotDomainMin ?? -10;
      const max = data.plotDomainMax ?? 10;
      const step = (max - min) / 100;
      try {
        const func = new Function('x', `return ${data.plotFormula};`);
        for (let x = min; x <= max; x += step) {
            const y = func(x);
            if (!isNaN(y) && isFinite(y)) points.push({ x: parseFloat(x.toFixed(2)), y: parseFloat(y.toFixed(2)) });
        }
        visual = { type: VisualType.PLOT, plotData: { points, label: `y = ${data.plotFormula}`, domain: [min, max] } };
      } catch (e) { console.error(e); }

    } else if (data.visualType === "PLOT3D" && data.plot3DFormula) {
        visual = { 
            type: VisualType.PLOT3D, 
            plot3DData: { 
                formula: data.plot3DFormula, 
                xRange: [-5, 5], 
                yRange: [-5, 5], 
                label: `z = ${data.plot3DFormula}` 
            } 
        };
    } else if (data.visualType === "FLOWCHART" && data.graphNodes && data.graphLinks) {
        visual = {
            type: VisualType.FLOWCHART,
            flowchartData: {
                nodes: data.graphNodes.map(n => ({ id: n.id, label: n.label, type: (n.type as any) || 'step' })),
                links: data.graphLinks
            }
        };
    } else if (data.visualType === "GRAPH" && data.graphNodes && data.graphLinks) {
        visual = {
            type: VisualType.GRAPH,
            graphData: { nodes: data.graphNodes, links: data.graphLinks }
        };
    } else if (data.visualType === "MATRIX" && data.matrixRows) {
        visual = {
            type: VisualType.MATRIX,
            matrixData: { matrix: data.matrixRows, label: "Matrix" }
        };
    }

    return {
      id: Date.now().toString(),
      role: 'model',
      text: data.explanation,
      visual: visual,
      suggestedActions: data.suggestedActions || ["Explain more", "Show an example"],
      timestamp: Date.now()
    };

  } catch (error) {
    console.error("Gemini API Error:", error);
    return {
      id: Date.now().toString(),
      role: 'model',
      text: "Squawk! I'm having trouble connecting to the math universe. Check your PROJECT or PROJECT_ID if required, or try again later.",
      visual: { type: VisualType.NONE },
      suggestedActions: ["Try again"],
      timestamp: Date.now()
    };
  }
};

