                    onClick={handleNewChat}
                    className="flex items-center gap-2 px-4 py-2 bg-brand-green text-white rounded-xl font-bold shadow-[0_3px_0_#46A302] hover:translate-y-0.5 hover:shadow-none transition-all text-sm"
                >
                    <Plus size={18} />
                    New Chat
                </button>
                <div className="flex items-center gap-2 text-slate-400 dark:text-slate-600">
                    {isSaving ? (
                        <span className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest animate-pulse">
                            <Save size={12} /> Saving...
                        </span>
                    ) : (
                        <span className="flex items-center gap-1.5 text-[10px] font-bold uppercase tracking-widest opacity-50">
                            Saved to coop
                        </span>
                    )}
                </div>
            </div>

            <button 
                onClick={handleClearHistory}
                className="p-2 text-slate-400 hover:text-brand-red hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                title="Clear all history"
            >
                <Eraser size={20} />
            </button>
        </div>

        <div className={`flex-1 overflow-y-auto z-10 p-4 pb-48 scrollbar-hide transition-all duration-300 ${showKeyboard ? 'pb-[320px]' : ''}`}>
            <div className="max-w-4xl mx-auto space-y-8">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-2`}>
                        <div className={`flex items-end gap-2 mb-2 px-1 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                            {msg.role === 'model' && <div className="mb-[-10px] z-10"><VoxelChicken size={50} /></div>}
                            {msg.role === 'user' && <div className="w-10 h-10 rounded-xl flex items-center justify-center border-2 bg-indigo-100 dark:bg-indigo-900 border-indigo-200 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400"><User size={20} /></div>}
                            <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">{msg.role === 'user' ? 'You' : 'Prof. Cluck'}</span>
                        </div>

                        <div className={`max-w-[90%] md:max-w-[85%] p-5 rounded-3xl shadow-sm text-lg leading-relaxed border-b-4 relative transition-colors ${msg.role === 'user' ? 'bg-indigo-500 text-white border-indigo-700 rounded-tr-sm' : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-700 dark:text-slate-200 rounded-tl-sm ml-4'}`}>
                            {msg.image && (
                                <div className="mb-4 rounded-2xl overflow-hidden border-2 border-white/20 shadow-lg">
                                    <img src={msg.image} alt="Submitted math" className="w-full h-auto object-contain max-h-[300px]" />
                                </div>
                            )}
                            <FormattedText text={msg.text} />
                        </div>

                        {msg.visual && msg.visual.type !== VisualType.NONE && (
                            <div className="mt-4 ml-4 w-full max-w-2xl bg-white dark:bg-slate-900 p-2 rounded-3xl border-2 border-slate-200 dark:border-slate-800 shadow-[0_8px_0_rgb(226,232,240)] dark:shadow-[0_8px_0_rgb(30,41,59)] overflow-hidden">
                                <div className="h-[350px] md:h-[500px] w-full">
                                    {msg.visual.type === VisualType.PLOT && msg.visual.plotData && <PlotVis data={msg.visual.plotData} />}
                                    {msg.visual.type === VisualType.PLOT3D && msg.visual.plot3DData && <Plot3DVis data={msg.visual.plot3DData} />}
                                    {msg.visual.type === VisualType.GRAPH && msg.visual.graphData && <GraphVis data={msg.visual.graphData} />}
                                    {msg.visual.type === VisualType.FLOWCHART && msg.visual.flowchartData && <FlowchartVis data={msg.visual.flowchartData} />}
                                    {msg.visual.type === VisualType.MATRIX && msg.visual.matrixData && <div className="h-full flex items-center justify-center"><MatrixVis data={msg.visual.matrixData} /></div>}
                                </div>
                            </div>
                        )}
                    </div>
                ))}
                {isLoading && (
                    <div className="flex flex-col items-start gap-2 animate-pulse">
                         <div className="flex items-end gap-2 px-1"><div className="mb-[-10px] z-10"><VoxelChicken size={50} emotion="thinking" /></div><span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-2">Thinking...</span></div>
                        <div className="bg-white dark:bg-slate-900 border-2 border-slate-200 dark:border-slate-800 p-4 rounded-3xl rounded-tl-sm shadow-sm ml-4"><Loader2 className="animate-spin text-brand-green" size={24} /></div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>
        </div>

        <div className="absolute bottom-0 left-0 right-0 z-20 flex flex-col">
            <div className="h-12 bg-gradient-to-t from-slate-100 dark:from-slate-950 to-transparent pointer-events-none" />

            {capturedImage && (
                <div className="max-w-4xl mx-auto w-full px-4 mb-2 animate-in slide-in-from-bottom-2">
                    <div className="bg-white dark:bg-slate-900 p-2 rounded-2xl border-2 border-brand-blue flex items-center gap-3 shadow-lg">
                        <div className="w-16 h-16 rounded-xl overflow-hidden border-2 border-slate-100 relative group">
                            <img src={capturedImage} className="w-full h-full object-cover" />
                            <button onClick={() => setCapturedImage(null)} className="absolute inset-0 bg-black/40 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-opacity">
                                <X size={20} />
                            </button>
                        </div>
                        <p className="text-xs font-bold text-slate-500 dark:text-slate-400">Math photo attached. What should Professor Cluck do with it?</p>
                    </div>
                </div>
            )}

            <div className="bg-slate-100/90 dark:bg-slate-900/90 backdrop-blur-md border-t border-slate-200 dark:border-slate-800 pb-2 pt-2 px-4">
                <div className="max-w-4xl mx-auto flex flex-col gap-3">
                    {!isLoading && !showKeyboard && currentSuggestedActions.length > 0 && (
                        <div className="flex flex-wrap gap-2 justify-center md:justify-start mb-2">
                            {currentSuggestedActions.map((action, idx) => (
                                <button key={idx} onClick={() => handleSend(action)} className="px-5 py-3 rounded-2xl bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 shadow-[0_4px_0_#e2e8f0] dark:shadow-[0_4px_0_#1e293b] hover:translate-y-1 hover:shadow-none hover:border-brand-blue hover:text-brand-blue font-bold text-slate-600 dark:text-slate-300 transition-all text-sm flex items-center gap-2 group">
                                    {action} <ArrowRight size={16} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                                </button>
                            ))}
                        </div>
                    )}
                    <div className="flex items-center gap-3 pb-4">
                        <button className="p-3 bg-white dark:bg-slate-800 border-2 border-slate-200 dark:border-slate-700 rounded-2xl text-slate-400 hover:text-brand-blue transition-colors" title="Snap Math" onClick={() => fileInputRef.current?.click()}>
                            <Camera size={20} />
                            <input type="file" ref={fileInputRef} accept="image/*" capture="environment" className="hidden" onChange={handleFileChange} />
                        </button>

                        <div className="flex-1 relative">
                            <input type="text" value={inputText} onChange={(e) => setInputText(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleSend(inputText, capturedImage)} placeholder="Ask Prof. Cluck..." disabled={isLoading} className="w-full p-4 pr-12 rounded-2xl border-2 outline-none font-medium text-slate-700 dark:text-slate-200 bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 focus:border-brand-blue focus:shadow-[0_4px_0_#1CB0F6]" />
                            <button onClick={() => setShowKeyboard(!showKeyboard)} className={`absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-brand-blue ${showKeyboard ? 'text-brand-blue bg-blue-50 dark:bg-blue-900/30' : ''}`}>{showKeyboard ? <X size={20} /> : <Keyboard size={20} />}</button>
                        </div>

                        <button onClick={() => handleSend(inputText, capturedImage)} disabled={(!inputText.trim() && !capturedImage) || isLoading} className={`p-4 rounded-2xl transition-all ${(inputText.trim() || capturedImage) && !isLoading ? 'bg-brand-green text-white shadow-[0_4px_0_#46A302] hover:translate-y-1 hover:shadow-none' : 'bg-slate-200 dark:bg-slate-800 text-slate-300 cursor-not-allowed'}`}><Send size={20} /></button>
                    </div>
                </div>
            </div>
            <MathKeyboard isOpen={showKeyboard} onInsert={(s) => setInputText(p => p + s)} onDelete={() => setInputText(p => p.slice(0, -1))} onEnter={() => handleSend(inputText, capturedImage)} />
        </div>
    </div>
  );
};

export default Whiteboard;

export enum VisualType {
  NONE = 'NONE',
  PLOT = 'PLOT',       // 2D functions like y = x^2
  PLOT3D = 'PLOT3D',   // 3D surfaces like z = x^2 + y^2
  GRAPH = 'GRAPH',     // Nodes and edges (trees, graph theory)
  FLOWCHART = 'FLOWCHART', // Algorithms or logical flows
  MATRIX = 'MATRIX'    // Matrix operations visual
}

export interface GraphNode {
  id: string;
  label?: string;
  group?: number;
}

export interface GraphLink {
  source: string;
  target: string;
  value?: number;
  label?: string;
}

export interface GraphData {
  nodes: GraphNode[];
  links: GraphLink[];
}

export interface PlotPoint {
  x: number;
  y: number;
}

export interface PlotData {
  points: PlotPoint[];
  label: string;
  domain: [number, number];
}

export interface Plot3DData {
  formula: string; // z in terms of x and y
  xRange: [number, number];
  yRange: [number, number];
  label: string;
}

export interface FlowchartNode {
  id: string;
  label: string;
  type: 'start' | 'step' | 'decision' | 'end';
}

export interface FlowchartData {
  nodes: FlowchartNode[];
  links: GraphLink[];
}

export interface MatrixData {
  matrix: number[][];
  label?: string;
}

export interface VisualContent {
  type: VisualType;
  graphData?: GraphData;
  plotData?: PlotData;
  plot3DData?: Plot3DData;
  matrixData?: MatrixData;
  flowchartData?: FlowchartData;
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string; // Base64 data URL
  visual?: VisualContent;
  suggestedActions?: string[]; 
  timestamp: number;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  updatedAt: number;
}

export interface Topic {
  id: string;
  name: string;
  description: string;
  color: string;
  icon: string;
  completed: number; // 0 to 100
}

export interface MathResponseSchema {
  explanation: string;
  visualType: string; // "PLOT" | "PLOT3D" | "GRAPH" | "FLOWCHART" | "MATRIX" | "NONE"
  suggestedActions: string[];
  // For Plot
  plotFormula?: string;
  plotDomainMin?: number;
  plotDomainMax?: number;
  // For Plot3D
  plot3DFormula?: string; // e.g. "Math.pow(x, 2) + Math.pow(y, 2)"
  // For Graph/Flowchart
  graphNodes?: { id: string; label: string; group?: number; type?: string }[];
  graphLinks?: { source: string; target: string; label?: string }[];
  // For Matrix
  matrixRows?: number[][];
}

export type View = 'auth' | 'path' | 'practice' | 'leaderboard' | 'shop';

import React, { useState, useRef, useEffect } from 'react';
import { Send, Eraser, Loader2, User, ArrowRight, Keyboard, X, Camera, Plus, Save, History, Trash2, Clock } from 'lucide-react';
import { Message, VisualType, ChatSession } from '../types';
import { sendMessageToGemini } from '../services/geminiService';
import PlotVis from './visualizations/PlotVis';
import Plot3DVis from './visualizations/Plot3DVis';
import GraphVis from './visualizations/GraphVis';
import FlowchartVis from './visualizations/FlowchartVis';
import MatrixVis from './visualizations/MatrixVis';
import MathKeyboard from './MathKeyboard';
import VoxelChicken from './VoxelChicken';

declare global {
  interface Window {
    katex: any;
  }
}

interface WhiteboardProps {
  initialTopic?: string;
  onXPChange?: (amount: number) => void;
}

const MATH_KEYWORDS = [
  'Derivative', 'Integral', 'Limit', 'Matrix', 'Vector', 'Eigenvector', 'Eigenvalue',
  'Determinant', 'Inverse', 'Linear Algebra', 'Calculus', 'Function', 'Graph', 
  'Discrete Math', 'Set Theory', 'Combinatorics', 'Probability', 'Statistics',
  'Logarithm', 'Exponential', 'Trigonometry', 'Sine', 'Cosine', 'Tangent',
  'Gradient', 'Divergence', 'Curl', 'Manifold', 'Topology', 'Equation',
  'Subspace', 'Basis', 'Dimension', 'Rank', 'Nullspace', 'Transformation',
  'Convergence', 'Divergence', 'Series', 'Sequence', 'Continuity', 'Taylor',
  'Fourier', 'Laplace', 'Differential', 'Partial', 'Chain Rule'
];

const MathRenderer: React.FC<{ tex: string; displayMode?: boolean }> = ({ tex, displayMode = false }) => {
  const html = React.useMemo(() => {
    try {
      if (window.katex) {
        return window.katex.renderToString(tex, {
          displayMode,
          throwOnError: false,
        });
      }
      return tex;
    } catch (e) {
      console.error("KaTeX Error:", e);
      return tex;
    }
  }, [tex, displayMode]);

  return <span className={displayMode ? "block my-4 overflow-x-auto scrollbar-hide py-2" : "inline-block"} dangerouslySetInnerHTML={{ __html: html }} />;
};

const FormattedText: React.FC<{ text: string }> = ({ text }) => {
  const keywordPattern = MATH_KEYWORDS.map(k => k.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|');
  const regex = new RegExp(`(\\$\\$[\\s\\S]*?\\$\\$)|(\\$.*?\\$)|(\\*\\*.*?\\*\\*)|\\b(${keywordPattern})\\b`, 'gi');
  const parts = text.split(regex);

  return (
    <div className="whitespace-pre-wrap">
      {parts.map((part, i) => {
        if (!part) return null;
        if (part.startsWith('$$') && part.endsWith('$$')) return <MathRenderer key={i} tex={part.slice(2, -2)} displayMode={true} />;
        if (part.startsWith('$') && part.endsWith('$')) return <MathRenderer key={i} tex={part.slice(1, -1)} />;
        if (part.startsWith('**') && part.endsWith('**')) return <strong key={i} className="text-brand-blue font-extrabold">{part.slice(2, -2)}</strong>;

        const isKeyword = MATH_KEYWORDS.some(k => k.toLowerCase() === part.toLowerCase());
        if (isKeyword) {
          return (
            <span key={i} className="px-1 py-0.5 rounded bg-brand-blue/10 dark:bg-brand-blue/20 text-brand-blue font-bold decoration-brand-blue/30 underline-offset-4 decoration-2">
              {part}
            </span>
          );
        }
        return <span key={i}>{part}</span>;
      })}
    </div>
  );
};

const SESSIONS_STORAGE_KEY = 'mathlingo_all_sessions';

const Whiteboard: React.FC<WhiteboardProps> = ({ initialTopic, onXPChange }) => {
  const getInitialMessage = (topic?: string): Message => ({
    id: 'welcome-' + Date.now(),
    role: 'model',
    text: topic 
      ? `Cluck cluck! Ready to dive back into **${topic}**? Let's crack some problems!` 
      : "Hi! I'm **Professor Cluck**. I can visualize anything from 3D surfaces to matrix transforms. What should we explore?",
    timestamp: Date.now(),
    visual: { type: VisualType.NONE },
    suggestedActions: topic 
      ? [`Explain ${topic} basics`, `Show me a ${topic} plot`, "Give me a quiz"] 
      : ["Plot 3D Surface", "Linear Transformations", "Graph Algorithms", "Calculate Integrals"]
  });

  const [sessions, setSessions] = useState<ChatSession[]>(() => {
    try {
        const saved = localStorage.getItem(SESSIONS_STORAGE_KEY);
        if (saved) {
            const parsed = JSON.parse(saved);
            if (Array.isArray(parsed) && parsed.length > 0) return parsed;
        }
    } catch (e) { console.error("Sessions load error:", e); }

    // Create first session if none exists
    const firstSession: ChatSession = {
        id: 'session-' + Date.now(),
        title: initialTopic || 'New Math Session',
        messages: [getInitialMessage(initialTopic)],
        updatedAt: Date.now()
    };
    return [firstSession];
  });

  const [currentSessionId, setCurrentSessionId] = useState<string>(sessions[0].id);
  const [inputText, setInputText] = useState('');
  const [capturedImage, setCapturedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [showKeyboard, setShowKeyboard] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const currentSession = sessions.find(s => s.id === currentSessionId) || sessions[0];
  const messages = currentSession.messages;

  // Persistence Effect
  useEffect(() => {
    setIsSaving(true);
    const timer = setTimeout(() => {
        localStorage.setItem(SESSIONS_STORAGE_KEY, JSON.stringify(sessions));
        setIsSaving(false);
    }, 500);
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    return () => clearTimeout(timer);
  }, [sessions]);

  const handleSend = async (text: string, image?: string | null) => {
    if ((!text.trim() && !image) || isLoading) return;

    const userMsg: Message = { 
        id: Date.now().toString(), 
        role: 'user', 
        text: text || "Help me with this!", 
        image: image || undefined,
        timestamp: Date.now() 
    };

    // Update local session state
    setSessions(prev => prev.map(s => {
        if (s.id === currentSessionId) {
            let newTitle = s.title;
            // Set title based on first user message if it's currently generic
            if (s.messages.length === 1 && text) {
                newTitle = text.slice(0, 30) + (text.length > 30 ? '...' : '');
            }
            return {
                ...s,
                title: newTitle,
                messages: [...s.messages, userMsg],
                updatedAt: Date.now()
            };
        }
        return s;
    }));

    setInputText('');
    setCapturedImage(null);
    setShowKeyboard(false);
    setIsLoading(true);

    try {
        const responseMsg = await sendMessageToGemini(messages, userMsg.text, image || undefined); 

        setSessions(prev => prev.map(s => {
            if (s.id === currentSessionId) {
                return {
                    ...s,
                    messages: [...s.messages, responseMsg],
                    updatedAt: Date.now()
                };
            }
            return s;
        }));

        if (onXPChange) onXPChange(image ? 25 : 10);
    } catch (e) { 
        console.error(e);
        const errMsg: Message = {
            id: 'err-' + Date.now(),
            role: 'model',
            text: "Oops! My feathers got ruffled. Try again?",
            timestamp: Date.now(),
            visual: { type: VisualType.NONE },
            suggestedActions: ["Try again"]
        };
        setSessions(prev => prev.map(s => {
            if (s.id === currentSessionId) {
                return { ...s, messages: [...s.messages, errMsg], updatedAt: Date.now() };
            }
            return s;
        }));
    } finally { 
        setIsLoading(false); 
    }
  };

  const handleNewChat = () => {
    const newSession: ChatSession = {
        id: 'session-' + Date.now(),
        title: 'New Math Session',
        messages: [getInitialMessage(initialTopic)],
        updatedAt: Date.now()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setIsHistoryOpen(false);
  };

  const deleteSession = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (sessions.length <= 1) {
        handleClearCurrentHistory();
        return;
    }
    const newSessions = sessions.filter(s => s.id !== id);
    setSessions(newSessions);
    if (currentSessionId === id) {
        setCurrentSessionId(newSessions[0].id);
    }
  };

  const handleClearCurrentHistory = () => {
    if (window.confirm("Clear this conversation?")) {
        setSessions(prev => prev.map(s => {
            if (s.id === currentSessionId) {
                return {
                    ...s,
                    title: 'New Math Session',
                    messages: [getInitialMessage(initialTopic)],
                    updatedAt: Date.now()
                };
            }
            return s;
        }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onloadend = () => setCapturedImage(reader.result as string);
          reader.readAsDataURL(file);
      }
  };

  const currentSuggestedActions = [...messages].reverse().find(m => m.role === 'model')?.suggestedActions || [];

  return (
    <div className="flex flex-col h-full bg-[#f8fafc] dark:bg-slate-950 relative overflow-hidden transition-colors duration-300">
        {/* History Drawer Overlay */}
        {isHistoryOpen && (
            <div 
                className="fixed inset-0 z-50 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300"
                onClick={() => setIsHistoryOpen(false)}
            >
                <div 
                    className="absolute left-0 top-0 bottom-0 w-80 bg-white dark:bg-slate-900 shadow-2xl p-6 border-r border-slate-200 dark:border-slate-800 flex flex-col animate-in slide-in-from-left duration-300"
                    onClick={e => e.stopPropagation()}
                >
                    <div className="flex items-center justify-between mb-8">
                        <div className="flex items-center gap-2">
                            <History className="text-brand-blue" size={24} />
                            <h2 className="text-xl font-extrabold text-slate-700 dark:text-slate-200">Math Coop</h2>
                        </div>
                        <button onClick={() => setIsHistoryOpen(false)} className="p-2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                            <X size={24} />
                        </button>
                    </div>

                    <button 
                        onClick={handleNewChat}
                        className="w-full flex items-center justify-center gap-2 py-4 mb-6 bg-brand-green text-white rounded-2xl font-bold shadow-[0_4px_0_#46A302] hover:translate-y-0.5 hover:shadow-none transition-all"
                    >
                        <Plus size={20} />
                        Fresh Start
                    </button>

                    <div className="flex-1 overflow-y-auto space-y-3 scrollbar-hide pr-2">
                        <p className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-[0.2em] mb-2 px-1">Recent Sessions</p>
                        {sessions.map(session => (
                            <div 
                                key={session.id}
                                onClick={() => { setCurrentSessionId(session.id); setIsHistoryOpen(false); }}
                                className={`group flex items-center justify-between p-4 rounded-2xl border-2 transition-all cursor-pointer ${
                                    session.id === currentSessionId 
                                    ? 'bg-blue-50 dark:bg-brand-blue/10 border-brand-blue' 
                                    : 'bg-white dark:bg-slate-800/50 border-slate-100 dark:border-slate-800 hover:border-slate-200 dark:hover:border-slate-700'
                                }`}
                            >
                                <div className="flex-1 min-w-0 pr-2">
                                    <p className={`font-bold truncate text-sm ${session.id === currentSessionId ? 'text-brand-blue' : 'text-slate-600 dark:text-slate-300'}`}>
                                        {session.title}
                                    </p>
                                    <div className="flex items-center gap-1.5 mt-1 text-[10px] text-slate-400 font-bold uppercase">
                                        <Clock size={10} />
                                        {new Date(session.updatedAt).toLocaleDateString()}
                                    </div>
                                </div>
                                <button 
                                    onClick={(e) => deleteSession(e, session.id)}
                                    className="p-2 text-slate-300 hover:text-brand-red opacity-0 group-hover:opacity-100 transition-all"
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        )}

        {/* Toolbar Header */}
        <div className="z-20 px-6 py-3 flex items-center justify-between border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md">
