import React, { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';
import { Plot3DData } from '../../types';
import { RotateCcw, ZoomIn, ZoomOut, Move } from 'lucide-react';

interface Plot3DVisProps {
  data: Plot3DData;
}

const Plot3DVis: React.FC<Plot3DVisProps> = ({ data }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const cameraRef = useRef<THREE.PerspectiveCamera | null>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const width = containerRef.current.clientWidth;
    const height = containerRef.current.clientHeight;

    const scene = new THREE.Scene();
    sceneRef.current = scene;
    scene.background = new THREE.Color(0xf8fafc);
    if (document.documentElement.classList.contains('dark')) {
      scene.background = new THREE.Color(0x0f172a);
    }

    const camera = new THREE.PerspectiveCamera(45, width / height, 0.1, 1000);
    cameraRef.current = camera;
    camera.position.set(10, 10, 10);
    camera.lookAt(0, 0, 0);

    const renderer = new THREE.WebGLRenderer({ antialias: true });
    rendererRef.current = renderer;
    renderer.setSize(width, height);
    containerRef.current.appendChild(renderer.domElement);

    const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
    scene.add(ambientLight);
    const directionalLight = new THREE.DirectionalLight(0xffffff, 1);
    directionalLight.position.set(10, 20, 10);
    scene.add(directionalLight);

    const axes = new THREE.AxesHelper(6);
    scene.add(axes);

    const segments = 60;
    const geometry = new THREE.PlaneGeometry(10, 10, segments, segments);
    geometry.rotateX(-Math.PI / 2);

    let func;
    try {
      func = new Function('x', 'y', `return ${data.formula};`);
    } catch (e) {
      func = (x: number, y: number) => 0;
    }

    const positions = geometry.attributes.position;
    for (let i = 0; i < positions.count; i++) {
      const x = positions.getX(i);
      const y = positions.getZ(i);
      try {
        const z = func(x, y);
        positions.setY(i, z);
      } catch (e) {
        positions.setY(i, 0);
      }
    }
    geometry.computeVertexNormals();

    const material = new THREE.MeshPhongMaterial({
      color: 0x1CB0F6,
      side: THREE.DoubleSide,
      flatShading: false,
      transparent: true,
      opacity: 0.85
    });
    const mesh = new THREE.Mesh(geometry, material);
    scene.add(mesh);

    const wireframe = new THREE.WireframeGeometry(geometry);
    const line = new THREE.LineSegments(wireframe);
    line.material.opacity = 0.15;
    line.material.transparent = true;
    line.material.color = new THREE.Color(0xffffff);
    scene.add(line);

    let isDragging = false;
    let dragMode: 'rotate' | 'pan' = 'rotate';
    let previousMousePosition = { x: 0, y: 0 };

    const onMouseDown = (e: MouseEvent) => { 
      isDragging = true; 
      dragMode = (e.button === 2 || e.shiftKey) ? 'pan' : 'rotate';
    };

    const onMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        const deltaMove = { x: e.offsetX - previousMousePosition.x, y: e.offsetY - previousMousePosition.y };

        if (dragMode === 'rotate') {
          const rotateQuaternion = new THREE.Quaternion().setFromEuler(new THREE.Euler(
            THREE.MathUtils.degToRad(deltaMove.y * 0.5),
            THREE.MathUtils.degToRad(deltaMove.x * 0.5),
            0,
            'XYZ'
          ));
          scene.quaternion.multiplyQuaternions(rotateQuaternion, scene.quaternion);
        } else {
          // Simple pan logic
          const panSpeed = 0.02;
          camera.position.x -= deltaMove.x * panSpeed;
          camera.position.y += deltaMove.y * panSpeed;
        }
      }
      previousMousePosition = { x: e.offsetX, y: e.offsetY };
    };

    const onMouseUp = () => { isDragging = false; };
    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const zoomSpeed = 0.005;
      const zoomFactor = 1 + e.deltaY * zoomSpeed;
      camera.position.multiplyScalar(zoomFactor);
    };

    const onContextMenu = (e: MouseEvent) => e.preventDefault();

    renderer.domElement.addEventListener('mousedown', onMouseDown);
    renderer.domElement.addEventListener('mousemove', onMouseMove);
    renderer.domElement.addEventListener('wheel', onWheel);
    renderer.domElement.addEventListener('contextmenu', onContextMenu);
    window.addEventListener('mouseup', onMouseUp);

    const animate = () => {
      requestAnimationFrame(animate);
      renderer.render(scene, camera);
    };
    animate();

    return () => {
      renderer.dispose();
      if (containerRef.current && renderer.domElement.parentNode === containerRef.current) {
          containerRef.current.removeChild(renderer.domElement);
      }
      renderer.domElement.removeEventListener('mousedown', onMouseDown);
      renderer.domElement.removeEventListener('mousemove', onMouseMove);
      renderer.domElement.removeEventListener('wheel', onWheel);
      renderer.domElement.removeEventListener('contextmenu', onContextMenu);
      window.removeEventListener('mouseup', onMouseUp);
    };
  }, [data]);

  const resetCamera = () => {
    if (cameraRef.current && sceneRef.current) {
      cameraRef.current.position.set(10, 10, 10);
      cameraRef.current.lookAt(0, 0, 0);
      sceneRef.current.quaternion.set(0, 0, 0, 1);
    }
  };

  return (
    <div className="w-full h-full relative group overflow-hidden rounded-3xl">
      <div className="absolute top-4 left-4 z-10 flex flex-col gap-2">
        <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur-md p-3 rounded-2xl border border-slate-200 dark:border-slate-700 pointer-events-none shadow-sm">
            <p className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1">3D Surface</p>
            <p className="text-sm font-mono font-bold text-brand-blue">{data.label}</p>
        </div>
        <div className="flex gap-2">
           <button onClick={resetCamera} className="p-2 bg-white/90 dark:bg-slate-800/90 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors text-slate-500" title="Reset Camera">
              <RotateCcw size={16} />
           </button>
           <div className="flex items-center gap-2 bg-white/90 dark:bg-slate-800/90 px-3 py-1 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm text-[10px] font-bold text-slate-400">
              <span className="flex items-center gap-1"><RotateCcw size={10}/> Drag</span>
              <span className="flex items-center gap-1"><Move size={10}/> Shift+Drag</span>
           </div>
        </div>
      </div>
      <div ref={containerRef} className="w-full h-full cursor-move bg-slate-50 dark:bg-slate-900" />
    </div>
  );
};

export default Plot3DVis;

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { GraphData, GraphNode, GraphLink } from '../../types';
import { Maximize, ZoomIn, ZoomOut } from 'lucide-react';

interface GraphVisProps {
  data: GraphData;
}

const GraphVis: React.FC<GraphVisProps> = ({ data }) => {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current || !data.nodes.length) return;

    const width = svgRef.current.clientWidth;
    const height = svgRef.current.clientHeight;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const isDark = document.documentElement.classList.contains('dark');
    const labelColor = isDark ? "#e2e8f0" : "#64748b";
    const nodeStroke = isDark ? "#0f172a" : "#ffffff";
    const linkColor = isDark ? "#475569" : "#94a3b8";

    // Main container for zoom
    const container = svg.append("g");

    // Zoom behavior
    const zoom = d3.zoom()
      .scaleExtent([0.1, 8])
      .on("zoom", (event) => {
        container.attr("transform", event.transform);
      });

    svg.call(zoom as any);

    const simulation = d3.forceSimulation(data.nodes as d3.SimulationNodeDatum[])
      .force("link", d3.forceLink(data.links).id((d: any) => d.id).distance(100))
      .force("charge", d3.forceManyBody().strength(-400))
      .force("center", d3.forceCenter(width / 2, height / 2))
      .force("collide", d3.forceCollide().radius(50));

    svg.append("defs").append("marker")
        .attr("id", "arrowhead")
        .attr("viewBox", "0 -5 10 10")
        .attr("refX", 35)
        .attr("refY", 0)
        .attr("markerWidth", 6)
        .attr("markerHeight", 6)
        .attr("orient", "auto")
        .append("path")
        .attr("d", "M0,-5L10,0L0,5")
        .attr("fill", linkColor);

    const link = container.append("g")
      .attr("stroke", linkColor)
      .attr("stroke-opacity", 0.6)
      .selectAll("line")
      .data(data.links)
      .join("line")
      .attr("stroke-width", 2)
      .attr("marker-end", "url(#arrowhead)");

    const nodeGroup = container.append("g")
      .selectAll("g")
      .data(data.nodes)
      .join("g")
      .call(d3.drag<any, any>()
        .on("start", dragstarted)
        .on("drag", dragged)
        .on("end", dragended)
      );

    nodeGroup.append("circle")
      .attr("r", 28)
      .attr("fill", (d: any) => d.group === 1 ? "#58CC02" : (d.group === 2 ? "#FFC800" : "#1CB0F6"))
      .attr("stroke", nodeStroke)
      .attr("stroke-width", 3)
      .attr("class", "shadow-sm cursor-grab active:cursor-grabbing transition-colors");

    nodeGroup.append("text")
      .text((d: any) => d.label || d.id)
      .attr("text-anchor", "middle")
      .attr("dy", ".35em")
      .attr("fill", "white")
      .attr("font-weight", "900")
      .attr("font-size", "13px")
      .attr("pointer-events", "none");

    simulation.on("tick", () => {
      link
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      nodeGroup.attr("transform", (d: any) => `translate(${d.x},${d.y})`);
    });

    function dragstarted(event: any, d: any) {
      if (!event.active) simulation.alphaTarget(0.3).restart();
      d.fx = d.x;
      d.fy = d.y;
    }

    function dragged(event: any, d: any) {
      d.fx = event.x;
      d.fy = event.y;
    }

    function dragended(event: any, d: any) {
      if (!event.active) simulation.alphaTarget(0);
      d.fx = null;
      d.fy = null;
    }

    return () => { simulation.stop(); };
  }, [data]);

  const handleResetZoom = () => {
    if (svgRef.current) {
      d3.select(svgRef.current).transition().duration(750).call(d3.zoom().transform as any, d3.zoomIdentity);
    }
  };

  return (
    <div className="w-full h-full bg-slate-50 dark:bg-slate-900/50 rounded-2xl border-2 border-slate-200 dark:border-slate-800 overflow-hidden relative transition-colors">
      <div className="absolute top-3 left-3 flex items-center gap-2 z-10">
        <div className="bg-white/80 dark:bg-slate-800/80 backdrop-blur px-3 py-1.5 rounded-xl text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest border border-slate-200 dark:border-slate-700 shadow-sm">
          Interactive Graph
        </div>
        <button onClick={handleResetZoom} className="p-1.5 bg-white/90 dark:bg-slate-800/90 rounded-lg border border-slate-200 dark:border-slate-700 text-slate-400 hover:text-brand-blue transition-colors shadow-sm" title="Reset View">
           <Maximize size={14} />
        </button>
      </div>
      <div className="absolute bottom-3 left-3 bg-white/60 dark:bg-slate-800/60 backdrop-blur px-2 py-1 rounded-lg text-[9px] font-bold text-slate-400 border border-slate-200 dark:border-slate-700 pointer-events-none">
        Pinch or Scroll to Zoom • Drag to Pan
      </div>
      <svg ref={svgRef} className="w-full h-full cursor-all-scroll" />
    </div>
  );
};

