        .text(d => d.label || "")
        .attr("fill", isDark ? "#94a3b8" : "#64748b")
        .attr("font-size", "10px")
        .attr("text-anchor", "middle")
        .attr("dy", -5);

    const node = container.append("g")
      .selectAll("g")
      .data(data.nodes)
      .join("g")
      .call(d3.drag<any, any>()
        .on("start", (e, d) => { if (!e.active) simulation.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
        .on("drag", (e, d) => { d.fx = e.x; d.fy = e.y; })
        .on("end", (e, d) => { if (!e.active) simulation.alphaTarget(0); d.fx = null; d.fy = null; }));

    node.each(function(d: any) {
      const g = d3.select(this);
      const label = d.label;

      if (d.type === 'decision') {
          g.append("path")
            .attr("d", "M 0 -35 L 50 0 L 0 35 L -50 0 Z")
            .attr("fill", "#FFC800")
            .attr("stroke", "white")
            .attr("stroke-width", 3);
      } else if (d.type === 'start' || d.type === 'end') {
          g.append("rect")
            .attr("x", -50).attr("y", -20).attr("width", 100).attr("height", 40).attr("rx", 20)
            .attr("fill", d.type === 'start' ? "#58CC02" : "#FF4B4B")
            .attr("stroke", "white").attr("stroke-width", 3);
      } else {
          g.append("rect")
            .attr("x", -55).attr("y", -25).attr("width", 110).attr("height", 50).attr("rx", 12)
            .attr("fill", "#1CB0F6")
            .attr("stroke", "white").attr("stroke-width", 3);
      }

      g.append("text")
        .text(label)
        .attr("text-anchor", "middle")
        .attr("dy", ".35em")
        .attr("fill", "white")
        .attr("font-weight", "900")
        .attr("font-size", "11px")
        .attr("pointer-events", "none");
    });

    simulation.on("tick", () => {
      link.select("line")
        .attr("x1", (d: any) => d.source.x)
        .attr("y1", (d: any) => d.source.y)
        .attr("x2", (d: any) => d.target.x)
        .attr("y2", (d: any) => d.target.y);

      link.select("text")
        .attr("x", (d: any) => (d.source.x + d.target.x) / 2)
        .attr("y", (d: any) => (d.source.y + d.target.y) / 2);

      node.attr("transform", (d: any) => `translate(${d.x},${d.y})`);
    });

    return () => simulation.stop();
  }, [data]);

  const resetView = () => {
    if (svgRef.current) {
      d3.select(svgRef.current).transition().duration(750).call(d3.zoom().transform as any, d3.zoomIdentity);
    }
  };

  return (
    <div className="w-full h-full min-h-[400px] bg-slate-50 dark:bg-slate-900/50 rounded-2xl border-2 border-slate-200 dark:border-slate-800 overflow-hidden transition-colors relative">
        <div className="absolute top-2 left-2 flex items-center gap-2 z-10">
          <div className="bg-white/80 dark:bg-slate-800/80 px-3 py-1.5 rounded-xl text-[10px] font-bold text-slate-500 z-10 uppercase tracking-widest border border-slate-200 dark:border-slate-700 shadow-sm">Process Flow</div>
          <button onClick={resetView} className="p-1.5 bg-white/90 dark:bg-slate-800/90 rounded-lg border border-slate-200 dark:border-slate-700 text-slate-400 hover:text-brand-blue transition-colors shadow-sm">
             <Maximize size={14} />
          </button>
        </div>
        <svg ref={svgRef} className="w-full h-full cursor-move" />
    </div>
  );
};

